const assert = require('assert');
const fs = require('fs');
const os = require('os');
const path = require('path');
const maintenance = require('../lib/markdown-maintenance');

const temp = fs.mkdtempSync(path.join(os.tmpdir(), 'markdown-maintenance-test-'));
const kbPath = path.join(temp, 'knowledge', 'demo');
const backupRoot = path.join(temp, 'knowledge', '.project-knowledge', '_backup', 'markdown-maintenance');

try {
  fs.mkdirSync(path.join(kbPath, 'modules'), { recursive: true });
  fs.mkdirSync(path.join(kbPath, 'changes'), { recursive: true });
  fs.writeFileSync(path.join(kbPath, 'README.md'), '\uFEFF# Demo\r\n\r\n\r\n\r\nUpdated: first\r\nUpdated: second', 'utf8');
  fs.writeFileSync(path.join(kbPath, 'GOAL.md'), '# Goal\n', 'utf8');
  fs.writeFileSync(path.join(kbPath, 'ARCHITECTURE.md'), '# Architecture\n', 'utf8');
  fs.writeFileSync(path.join(kbPath, 'modules', 'core.md'), '---\ntitle: Core\ntags: [one, two, three, four, five]\n---\n# Core\n\n## State\nCurrent.\n\n## State\nOld appended state.\n', 'utf8');
  fs.writeFileSync(path.join(kbPath, 'modules', 'broken.md'), '---\ntitle: Broken\ntags: [repairable]\n\n# Broken\n\n```text\nunclosed\n', 'utf8');
  fs.writeFileSync(path.join(kbPath, 'changes', 'change.md'), '---\ntitle: Change\nupdatedAt: 2026-07-16\n---\n# Change\n', 'utf8');
  fs.writeFileSync(path.join(kbPath, 'modules', '00-index.md'), '# Old Index\n\nTags: one, two, three\n', 'utf8');
  fs.writeFileSync(path.join(kbPath, 'changes', '00-index.md'), '# Old Changes\n', 'utf8');

  const before = maintenance.auditKnowledgeBase('demo', kbPath);
  assert(before.fixableCount >= 3, 'audit should find format and stale-index issues');
  assert(before.reviewCount >= 2, 'audit should flag repeated metadata and duplicate heading paths for review');
  assert.equal(before.errorCount, 2, 'audit should detect repairable malformed frontmatter and code fence errors');
  assert(before.issues.some(item => item.code === 'derived-index-stale'), 'stale generated index should be detected');

  const optimized = maintenance.optimizeKnowledgeBase({ slug: 'demo', kbPath, backupRoot, batchId: 'batch-test' });
  assert(optimized.changed.includes('README.md'), 'safe Markdown formatting should be normalized');
  assert(optimized.changed.includes('modules/00-index.md'), 'module index should be rebuilt from scratch');
  assert(fs.existsSync(path.join(optimized.backupDir, 'README.md')), 'changed source files should be backed up');
  assert(fs.existsSync(path.join(optimized.backupDir, 'modules', '00-index.md')), 'replaced derived indexes should be backed up');
  const readme = fs.readFileSync(path.join(kbPath, 'README.md'), 'utf8');
  assert(!readme.startsWith('\uFEFF') && readme.endsWith('\n'), 'normalization should remove BOM and add final newline');
  const index = fs.readFileSync(path.join(kbPath, 'modules', '00-index.md'), 'utf8');
  assert(index.startsWith('<!-- Generated by project-knowledge.'), 'rebuilt index should use the compact generated format');
  assert(!/^Tags:/m.test(index), 'rebuilt index should not aggregate tags');
  assert(optimized.after.fixableCount === 0, 'all deterministic issues should be fixed');
  assert.equal(optimized.after.errorCount, 0, 'repairable structural errors should be fixed');
  const repaired = fs.readFileSync(path.join(kbPath, 'modules', 'broken.md'), 'utf8');
  assert(/^---\ntitle: Broken\ntags: \[repairable\]\n\n---\n/m.test(repaired), 'missing frontmatter delimiter should be restored before the first heading');
  assert(repaired.trimEnd().endsWith('```'), 'unclosed code fence should be closed at end of file');
  assert(optimized.after.reviewCount >= 2, 'semantic consolidation findings should remain visible for review');

  const projects = maintenance.auditProjects({
    demo: { kbPath, enabled: true, knowledgeBackend: 'lancedb' },
    alias: { kbPath, enabled: true, teamKnowledge: { enabled: true } },
  });
  assert.equal(projects.summary.projects, 1, 'shared/team KB paths should be audited only once');
  assert.deepEqual(projects.projects[0].aliases, ['alias']);

  console.log('markdown-maintenance-test: PASS');
} finally {
  fs.rmSync(temp, { recursive: true, force: true });
}
